'use client';

import React, { useCallback } from 'react';
import { Button, Tooltip, ButtonProps } from 'antd';
import { debounce } from 'lodash'; // Cần cài đặt: npm i lodash @types/lodash
import { useTheme } from '@/lib/ThemeProvider';
import { usePermission } from '@/lib/PermissionProvider';

/**
 * AppButtonProps sử dụng Generic <T> để truyền dữ liệu tùy ý vào sự kiện click
 * Tương đương với việc truyền tham số vào delegate/action trong C#
 */
interface AppButtonProps<T = any> extends Omit<ButtonProps, 'onClick'> {
    title?: string; // Nội dung Tooltip khi hover
    btnType?: 'add' | 'export' | 'filter' | 'edit' | 'delete' | 'view';
    data?: T; // Dữ liệu đính kèm (ví dụ: object record, string id)
    permission?: string | string[]; // Key phân quyền (ví dụ: 'product.delete')
    useDebounce?: boolean; // Chống click liên tục (mặc định false)
    onClick?: (e: React.MouseEvent<HTMLElement>, data?: T) => void;
}

export const AppButton = <T,>({
    title,
    icon,
    style,
    btnType,
    className,
    children,
    onClick,
    data,
    permission,
    useDebounce = false,
    ...props
}: AppButtonProps<T>) => {
    const { primaryColor } = useTheme();
    const { hasPermission } = usePermission();

    // Kiểm tra quyền truy cập dựa trên hook usePermission
    const canAccess = !permission || hasPermission(permission);

    // Nếu không có quyền thì không hiển thị nút
    if (!canAccess) return null;



    /**
     * Cấu hình Style dựa trên loại Button
     * Đảm bảo bo góc 6px đồng bộ với layout.tsx
     */
    const getConfigs = () => {
        const themeBackground = { backgroundColor: primaryColor, color: 'white', ...style };
        const roundedClass = 'rounded-md flex items-center justify-center';



        switch (btnType) {
            case 'add':
                return {
                    type: 'primary' as const,
                    style: themeBackground,
                    className: `${roundedClass}`
                };
            case 'export':
                return {
                    style: themeBackground,
                    className: `${roundedClass}`
                };
            case 'delete':
                return {
                    danger: true,
                    type: 'text' as const,
                    className: `${roundedClass} hover:bg-red-50`
                };
            case 'edit':
                return {
                    type: 'text' as const,
                    className: `${roundedClass} hover:bg-orange-50`
                };
            case 'view':
                return {
                    type: 'default' as const,
                    className: `${roundedClass} border-primary`,
                    style: {
                        borderColor: props.disabled ? undefined : primaryColor,
                        color: props.disabled ? undefined : primaryColor,
                        ...style
                    }
                };
            default:
                return {
                    className: `${roundedClass} border-gray-300`,
                    style: themeBackground
                };
        }
    };

    const config = getConfigs();

    /**
     * Xử lý Debounce: Trì hoãn 300ms để tránh việc user click liên tục 
     * gây lỗi hoặc gọi API dư thừa
     */
    const debouncedClick = useCallback(
        debounce((e: React.MouseEvent<HTMLElement>, d?: T) => {
            onClick?.(e, d);
        }, 300),
        [onClick]
    );

    const handleClick = (e: React.MouseEvent<HTMLElement>) => {
        e.stopPropagation(); // Ngăn chặn sự kiện click lan ra các phần tử cha (như hàng của Table)

        if (useDebounce) {
            debouncedClick(e, data);
        } else {
            onClick?.(e, data);
        }
    };

    const buttonElement = (
        <Button
            {...config}
            {...props}
            icon={icon}
            onClick={handleClick}
            className={`${config.className} ${className || ''}`}
        >
            {children}
        </Button>
    );

    // Nếu có tiêu đề thì bọc trong Tooltip để tối ưu trải nghiệm người dùng
    return title ? (
        <Tooltip title={title} mouseEnterDelay={0.5}>
            {buttonElement}
        </Tooltip>
    ) : (
        buttonElement
    );
};